    if conversion_format.lower() == 'pdf':
        command = ['libreoffice', '--headless', '--convert-to', 'pdf', input_file, '--outdir', os.path.dirname(output_file)]
    elif conversion_format.lower() == 'docx':
        command = ['libreoffice', '--headless', '--convert-to', 'docx', input_file, '--outdir', os.path.dirname(output_file)]
